import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const OUTPUT = path.join(ROOT, "map-editor-standalone.js");
const SOURCES = ["map-editor-contract.js", "map-editor-core.js", "map-editor.js"];

function classicSource(source, filename) {
  let result = source.replace(/^\uFEFF/, "").trimStart();
  while (result.startsWith("import ")) {
    const end = result.indexOf(";");
    if (end < 0) throw new Error(`Import sin terminar en ${filename}`);
    result = result.slice(end + 1).trimStart();
  }
  return result.replace(/^export\s+/gm, "").trimEnd();
}

export async function buildMapEditorBundle() {
  const parts = await Promise.all(SOURCES.map(async (filename) => ({
    filename,
    source: classicSource(await readFile(path.join(ROOT, filename), "utf8"), filename),
  })));
  return [
    "/* AUTO-GENERATED by tools/build-map-editor-bundle.mjs. Do not edit directly. */",
    "(() => {",
    "  \"use strict\";",
    ...parts.flatMap(({ filename, source }) => [`\n  /* ${filename} */`, source]),
    "})();",
    "",
  ].join("\n");
}

async function main() {
  const expected = await buildMapEditorBundle();
  if (process.argv.includes("--check")) {
    const current = await readFile(OUTPUT, "utf8").catch(() => "");
    if (current !== expected) {
      console.error("map-editor-standalone.js no está actualizado. Ejecuta npm run editor:bundle.");
      process.exitCode = 1;
      return;
    }
    console.log("OK: map-editor-standalone.js está actualizado.");
    return;
  }
  await writeFile(OUTPUT, expected, "utf8");
  console.log(`Generado ${path.relative(ROOT, OUTPUT)}`);
}

if (process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url)) await main();
